// // This module implements a transparent latch where ECK is set to '0' when SE is high and ECK is set to '1' when E is high.
module top_module( E, SE, CK, ECK );input E, SE, CK;
  output ECK;

  reg ECK;

  always @(posedge CK) begin
    if (SE) begin
      ECK <= 1'b1;
    end else if (E) begin
      ECK <= 1'b0;
    end
  end
endmodule
